// Some subject names will not conform to the RFC format
// For CN values containing DN-special characters like "=", use RFC2253 escaping
private static X500Principal subjectToX500Principle(String subject) {
    if (subject.startsWith("CN=")) {
        // Assume it's already a DN string (e.g., test certificate creation)
        return new X500Principal(subject);
    }
    // Escape CN value properly so that characters like "=", ",", "+", etc. are handled
    String escaped = Rdn.escapeValue(subject).toString();
    return new X500Principal("CN=" + escaped);
}

