package org.keycloak.util;

import java.security.KeyPair;
import java.security.cert.X509Certificate;

import org.keycloak.common.util.CertificateUtils;
import org.keycloak.common.util.KeyUtils;
import org.keycloak.rule.CryptoInitRule;

import org.junit.Assert;
import org.junit.ClassRule;
import org.junit.Test;

/**
 * Test that certificate generation works with special characters in subject,
 * e.g. SAML Client IDs that are URLs containing query-string characters.
 */
public abstract class CertificateUtilsTest {

    @ClassRule
    public static CryptoInitRule cryptoInitRule = new CryptoInitRule();

    @Test
    public void testCertificateWithUrlQueryString() {
        String subject = "https://example.com/?action=sso_id";
        assertCertificateGeneration(subject);
    }

    @Test
    public void testCertificateWithSpecialChars() {
        String[] subjects = new String[] {
            "https://example.com/?action=sso_id",
            "https://example.com/sp?a=b&c=d",
            "client:id/with/slashes",
            "client=with=equals",
            "client:with:colons",
            "client&with&ampersand",
            "client,with,comma",
            "client+plus",
            "CN=already, but tricky =? & / :",
            "  leading and trailing  ",
            "#hashStart"
        };
        for (String subject : subjects) {
            assertCertificateGeneration(subject);
        }
    }

    @Test
    public void testCertificateWithAllRequiredChars() {
        // Explicitly test characters mentioned in the issue: =, ?, /, :, &
        String subject = "https://example.com/test?param1=value1&param2=value2:8080/path";
        assertCertificateGeneration(subject);
    }

    private void assertCertificateGeneration(String subject) {
        try {
            KeyPair keyPair = KeyUtils.generateRsaKeyPair(2048);
            X509Certificate cert = CertificateUtils.generateV1SelfSignedCertificate(keyPair, subject);
            Assert.assertNotNull("Certificate should be generated for subject: " + subject, cert);
            Assert.assertNotNull("Cert subject should not be null", cert.getSubjectX500Principal());
            // The cert's subject should contain CN
            String subjectDN = cert.getSubjectX500Principal().getName();
            Assert.assertTrue("Subject DN should contain CN", subjectDN.contains("CN="));
        } catch (Exception e) {
            Assert.fail("Failed to generate certificate for subject [" + subject + "]: " + e.getMessage());
        }
    }
}

