import org.bouncycastle.asn1.x500.X500Name;
import org.bouncycastle.asn1.x500.X500NameBuilder;
import org.bouncycastle.asn1.x500.style.BCStyle;

public class TestBC {
    public static void main(String[] args) {
        String[] subjects = new String[] {
            "https://example.com/?action=sso_id",
            "https://example.com/sp?a=b&c=d",
            "client:id/with/slashes",
            "client=with=equals",
            "client:with:colons",
            "client&with"
        };
        System.out.println("Testing OLD approach: new X500Name(\"CN=\"+subject)");
        for (String s : subjects) {
            try {
                X500Name dn = new X500Name("CN=" + s);
                System.out.println("OLD OK for: " + s + " -> " + dn);
            } catch (Exception e) {
                System.out.println("OLD FAIL for: " + s + " -> " + e.getMessage());
            }
        }
        System.out.println("\nTesting NEW approach: builder.addRDN(CN, subject)");
        for (String s : subjects) {
            try {
                X500NameBuilder builder = new X500NameBuilder(BCStyle.INSTANCE);
                builder.addRDN(BCStyle.CN, s);
                X500Name dn = builder.build();
                System.out.println("NEW OK for: " + s + " -> " + dn);
            } catch (Exception e) {
                System.out.println("NEW FAIL for: " + s + " -> " + e.getMessage());
            }
        }
    }
}
