private static X500Name createSubjectDN(String subject) {
    // Use X500NameBuilder with DERUTF8String to safely handle special characters
    // such as "=", ",", "+", "#", etc. This prevents malformed DN when subject
    // contains URL query strings or other DN-special characters.
    // Using DERUTF8String bypasses string-to-value parsing that would otherwise
    // interpret leading "#" as hex encoding.
    X500NameBuilder builder = new X500NameBuilder(BCStyle.INSTANCE);
    builder.addRDN(BCStyle.CN, new DERUTF8String(subject));
    return builder.build();
}

